async reorder(orderedIds: string[]) {
  const updates = orderedIds.map((id, index) =>
    this.prisma.leaveTypeConfig.update({
      where: { id },
      data: { sortOrder: index },
    }),
  );

  await this.prisma.$transaction(updates);

  return this.findAll();
}

